_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


caval = q22/10;
wival = q22/10;
bright = q22;

    // Normalized pixel coordinates (from 0 to 1)
    //vec2 vUv = openfl_TextureCoordv; //I don't need to recalculate the vUv coord.

    vUv.x += sin(vUv.y*100.+uTime*3.25)*wival;
    vUv.y += sin(vUv.x*100.+uTime*3.25)*wival;

    vec2 uvr = vUv-vec2(sin(uTime)*caval, cos(uTime)*caval);
    vec2 uvb = vUv+vec2(sin(uTime)*caval, cos(uTime)*caval);

    vec4 col = vec4(texture(sampler_main, vUv).r, texture(sampler_main, vUv).g, texture(sampler_main, vUv).b, texture(sampler_main, vUv).a);
    col.rgb *= bright+1;
        vec2 uv2;

    vec4 c = vec4(1,0.4,0.15,0.1);

    uv2 = vUv + vec2(1,0)*uTexSize.zw;
    float gx1 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;
    uv2 = vUv + vec2(-1,0)*uTexSize.zw;
    float gx2 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;

    uv2 = vUv + vec2(0,1)*uTexSize.zw;
    float gy1 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;
    uv2 = vUv + vec2(0,-1)*uTexSize.zw;
    float gy2 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;

    vec3 g = normalize(vec3(gx1-gx2, gy1-gy2, 0.14));

    ret = 0.5 + 0.5*g;
    ret *= clamp01(length(ret.xy-0.5)*5);
    ret = ret.xxy;
    ret += 1.15;
    ret *= mix(ret,ret*(GetBlur3(vUv)-GetBlur1(vUv)*audioHighSmooth),pow(hue_shader.xzy,audioLowSmooth));
    ret *= ret;

  fragColor = ret;
}
